<Stats id="monster-rhu_chalik--stats" atts={[16,16,19,13,14,15]} bab={6} cmb={8} cmd={21} feats={["Combat Expertise","Combat Reflexes","Improved Initiative",["Weapon Focus"," (tendril)"]]} skills={{"bluff":{"b":8},"diplo":{"b":8},"sm":{"b":7},"stl":{"b":15},"umd":{"b":10}}} lang={["Ak",";",[<><Link to="/umr/telepathy">telepathy</Link> 100 ft.</>]]} sq={<><Link to="/umr/compression">compression</Link>, <Link to="/umr/no_breath">no breath</Link></>} />
